export const 鎮宅時氣 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    const 桿 = (x0, x1, z) => {
        線(p => p.M(X(x0) + 0.32 * k, Z(z)).L(X(x1) - 0.32 * k, Z(z)));
        圈(x0, z);
        圈(x1, z);
    };
    // 符頭
    桿(0.6, 7.2, 1.0);
    桿(0.6, 7.2, 2.2);
    const 心 = [3.4, 4.3];
    圈(心[0], 心[1]);
    for (const t of [[1.3, 3.3], [2.9, 2.95], [4.3, 2.9], [1.3, 4.4], [1.4, 5.7]]) {
        連(心, [t[0], t[1]]);
        圈(t[0], t[1]);
    }
    圈(3.1, 5.9);
    連([3.1, 5.9], [2.5, 6.6]);
    連([3.1, 5.9], [3.7, 6.35]);
    圈(2.5, 6.6);
    圈(3.7, 6.35);
    for (const [x, z] of [[5.7, 2.9], [5.9, 4.3], [6.1, 5.5], [4.9, 6.8], [6.3, 6.7]])
        圈(x, z);
    // 目田疊帶
    線(p => p.M(X(7.2), Z(7.6)).L(X(7.2), Z(17.8))); // 右軌
    線(p => p.M(X(0.8), Z(7.75)).L(X(7.0), Z(7.65)), 0.42);
    線(p => p.M(X(0.9), Z(8.5)).L(X(7.0), Z(8.4)));
    線(p => p.M(X(0.8), Z(9.3)).L(X(0.8), Z(11.6)));
    for (const z of [9.3, 10.45, 11.6])
        線(p => p.M(X(0.8), Z(z)).L(X(7.0), Z(z - 0.06)));
    線(p => p.M(X(0.8), Z(11.9)).L(X(0.8), Z(13.4)).L(X(6.6), Z(13.35))
        .L(X(6.6), Z(11.85)).L(X(0.75), Z(11.9)));
    線(p => p.M(X(3.7), Z(11.95)).L(X(3.65), Z(13.35)));
    線(p => p.M(X(0.9), Z(12.65)).L(X(6.5), Z(12.6)));
    // 山迴脚（boustro三折）＋右軌撇
    線(p => p.M(X(0.9), Z(13.8)).L(X(4.7), Z(13.75))
        .C(X(5.2), Z(13.75), X(5.2), Z(14.6), X(4.7), Z(14.65))
        .L(X(1.6), Z(14.7)).C(X(1.1), Z(14.7), X(1.1), Z(15.5), X(1.6), Z(15.55))
        .L(X(4.6), Z(15.5)).C(X(5.1), Z(15.5), X(5.1), Z(16.3), X(4.6), Z(16.35))
        .L(X(1.5), Z(16.4)).C(X(1.0), Z(16.45), X(0.9), Z(17.0), X(1.0), Z(17.6)));
    線(p => p.M(X(1.0), Z(17.9)).C(X(0.9), Z(18.4), X(0.9), Z(18.9), X(0.95), Z(19.2)));
    線(p => p.M(X(7.2), Z(17.9)).C(X(7.3), Z(18.4), X(7.3), Z(18.9), X(7.25), Z(19.2)));
};
